mapper.select:
SELECT 
FROM reservation r
WHERE r.reservation_number = #{reservationNumber}

SELECT ,
       u.username
FROM reservation r
LEFT JOIN user u ON r.user_id = u.id
WHERE r.seat_id = #{seatId}
  AND r.status != 4
  AND DATE(r.start_time) <= #{date}
  AND DATE(r.end_time) >= #{date}
ORDER BY r.start_time ASC

