UPDATE reservation
status = #{status}, payment_status = #{paymentStatus}, payment_time = #{paymentTime}, amount = #{amount}, trade_no = #{tradeNo}, refund_amount = #{refundAmount}, refund_time = #{refundTime}, refund_status = #{refundStatus}, refund_reason = #{refundReason},
WHERE id = #{id}
